blocks.body:
{
    "level": "B1",
    "intro": "W tym temacie dowiesz się szczegółowo <strong>Present Continuous Passive</strong>: jak utworzyć tę formę, kiedy jej używać i czym różni się ona od czasu Present Simple Passive.",
    "rules": [
        {
            "label": "Formuła",
            "color": "emerald",
            "text": "<strong>Temat + jestem/jest/jestem + istota + V3</strong>:",
            "example": "The house is being painted right now."
        },
        {
            "label": "Odmowa",
            "color": "rose",
            "text": "<strong>Temat + jestem/jest/jestem + nie + jestem + V3</strong>:",
            "example": "The report is not being written now."
        },
        {
            "label": "Pytanie",
            "color": "blue",
            "text": "<strong>Jestem/jest/jestem + podmiot + istota + V3?</strong>:",
            "example": "Is the project being developed?"
        }
    ]
}

{
    "title": "1. Struktura czasu teraźniejszego ciągłego biernego",
    "intro": "Forma czasownika <strong>być</strong> zależy od podmiotu, a słowo <strong>bycie</strong> pozostaje niezmienione:",
    "items": [
        {
            "label": "I",
            "title": "jestem + V3",
            "subtitle": "Teraz udzielam wywiadu. - Mam teraz przesłuchanie."
        },
        {
            "label": "On/ona/ono",
            "title": "jest + V3",
            "subtitle": "Samochód jest naprawiany. - Samochód jest w naprawie."
        },
        {
            "label": "Ty/My/Oni",
            "title": "są + V3",
            "subtitle": "Trwa sprawdzanie dokumentów. – Trwa sprawdzanie dokumentów."
        },
        {
            "label": "Klawisz",
            "title": "byt jest niezmienną częścią",
            "subtitle": "byt zawsze poprzedza V3."
        }
    ]
}

{
    "title": "2. Zdania twierdzące",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Kolejność słów: <strong>Temat + jestem/jest/jestem + istota + V3 (+ według agenta)</strong>",
            "examples": [
                {
                    "en": "The house is being painted at the moment.",
                    "ua": "Obecnie dom jest malowany."
                },
                {
                    "en": "The documents are being prepared right now.",
                    "ua": "Dokumenty są w trakcie przygotowywania."
                },
                {
                    "en": "I am being trained for the new position.",
                    "ua": "Szkolę się do nowego stanowiska."
                },
                {
                    "en": "The road is being repaired this week.",
                    "ua": "W tym tygodniu droga będzie naprawiana."
                }
            ]
        },
        {
            "label": "Procesy tymczasowe",
            "color": "sky",
            "description": "W przypadku działań, które <strong>trwają przez określony czas</strong>:",
            "examples": [
                {
                    "en": "A new system is being installed this month.",
                    "ua": "Nowy system jest instalowany w tym miesiącu."
                },
                {
                    "en": "The building is being renovated.",
                    "ua": "Budynek jest w remoncie (obecnie tymczasowym)."
                },
                {
                    "en": "New software is being tested at the moment.",
                    "ua": "Nowe oprogramowanie jest obecnie testowane."
                }
            ]
        }
    ]
}

{
    "title": "3. Kiedy używać strony biernej w czasie Present Continuous?",
    "sections": [
        {
            "label": "Akcja już teraz",
            "color": "emerald",
            "description": "W przypadku działań <strong>dokonujących się w momencie wypowiedzi</strong>:",
            "examples": [
                {
                    "en": "The dinner is being cooked right now.",
                    "ua": "Kolacja jest właśnie przygotowywana."
                },
                {
                    "en": "The meeting is being held at the moment.",
                    "ua": "Spotkanie obecnie się odbywa."
                },
                {
                    "en": "Your order is being processed.",
                    "ua": "Twoje zamówienie jest przetwarzane."
                }
            ]
        },
        {
            "label": "Sytuacje przejściowe",
            "color": "blue",
            "description": "W przypadku działań, które <strong>trwają przez określony czas</strong>, ale nie na stałe:",
            "examples": [
                {
                    "en": "The bridge is being constructed this year.",
                    "ua": "Most budowany jest w tym roku."
                },
                {
                    "en": "New employees are being trained this month.",
                    "ua": "W tym miesiącu przechodzą szkolenia nowi pracownicy."
                },
                {
                    "en": "The project is being developed at present.",
                    "ua": "Projekt jest aktualnie opracowywany."
                }
            ]
        },
        {
            "label": "Zmiany i trendy",
            "color": "amber",
            "description": "Aby opisać <strong>bieżące zmiany</strong>:",
            "examples": [
                {
                    "en": "More and more trees are being planted.",
                    "ua": "Sadzi się coraz więcej drzew."
                },
                {
                    "en": "The old system is being replaced gradually.",
                    "ua": "Stary system jest stopniowo zastępowany."
                },
                {
                    "en": "Electric cars are being promoted heavily.",
                    "ua": "Samochody elektryczne aktywnie się rozwijają."
                }
            ]
        }
    ]
}

{
    "title": "4. Zdania przeczące",
    "sections": [
        {
            "label": "Struktura",
            "color": "rose",
            "description": "Dodaj <strong>nie</strong> po am/jest/są: <strong>Temat + jestem/jest/są + nie + jest + V3</strong>",
            "examples": [
                {
                    "en": "The report is not being written at the moment.",
                    "ua": "Raport nie jest teraz pisany."
                },
                {
                    "en": "The rooms are not being cleaned today.",
                    "ua": "Pokoje nie są dziś sprzątane."
                },
                {
                    "en": "I am not being considered for the job.",
                    "ua": "Nie jestem brany pod uwagę na tym stanowisku."
                },
                {
                    "en": "The problem is not being addressed.",
                    "ua": "Problem nie został rozwiązany."
                }
            ]
        },
        {
            "label": "Skrócone formy",
            "color": "amber",
            "description": "Potocznie: <strong>nie jest / nie jest</strong>",
            "examples": [
                {
                    "en": "The car isn't being repaired today.",
                    "ua": "Samochód nie będzie dzisiaj naprawiany."
                },
                {
                    "en": "The packages aren't being delivered now.",
                    "ua": "Przesyłki nie są obecnie dostarczane."
                },
                {
                    "en": "The issue isn't being investigated.",
                    "ua": "Sprawa nie jest badana."
                }
            ]
        }
    ]
}

{
    "title": "5. Zdania pytające",
    "sections": [
        {
            "label": "Pytanie Tak/Nie",
            "color": "blue",
            "description": "<strong>Jestem/jest/jestem</strong> na pierwszym miejscu: <strong>jestem/jest/jestem + podmiot + istota + V3?</strong>",
            "examples": [
                {
                    "en": "Is the house being painted?",
                    "ua": "Czy dom jest malowany?"
                },
                {
                    "en": "Are the documents being checked?",
                    "ua": "Czy dokumenty są sprawdzane?"
                },
                {
                    "en": "Am I being tested?",
                    "ua": "Czy jestem testowany?"
                },
                {
                    "en": "Is the project being developed?",
                    "ua": "Czy projekt jest w trakcie opracowywania?"
                }
            ]
        },
        {
            "label": "Jakie pytanie",
            "color": "sky",
            "description": "<strong>Jakie-słowo + jestem/jest/są + Temat + istota + V3?</strong>",
            "examples": [
                {
                    "en": "What is being built there?",
                    "ua": "Co się tam buduje?"
                },
                {
                    "en": "Why is the road being closed?",
                    "ua": "Dlaczego droga jest zablokowana?"
                },
                {
                    "en": "Where are the tests being conducted?",
                    "ua": "Gdzie odbywają się testy?"
                },
                {
                    "en": "How is the problem being solved?",
                    "ua": "Jak problem został rozwiązany?"
                }
            ]
        },
        {
            "label": "Krótkie odpowiedzi",
            "color": "amber",
            "description": "Odpowiedzi zawierające <strong>Tak/Nie + zaimek + am/is/are (nie)</strong>:",
            "examples": [
                {
                    "en": "Is the car being repaired? — Yes, it is. / No, it isn't.",
                    "ua": "Czy samochód jest naprawiany? - Tak. / NIE."
                },
                {
                    "en": "Are they being interviewed? — Yes, they are. / No, they aren't.",
                    "ua": "Czy są przeprowadzani wywiad? - Tak. / NIE."
                }
            ]
        }
    ]
}

{
    "title": "6. Porównanie czasu aktywnego i pasywnego w czasie Present Continuous",
    "intro": "Jak zamienić zdanie czynne w stronę bierną:",
    "rows": [
        {
            "en": "Active: They are painting the house now.",
            "ua": "Aktualnie malują dom.",
            "note": "→ Passive: The house is being painted now."
        },
        {
            "en": "Active: The manager is checking the documents.",
            "ua": "Menedżer sprawdza dokumenty.",
            "note": "→ Passive: The documents are being checked."
        },
        {
            "en": "Active: Workers are repairing the road.",
            "ua": "Robotnicy naprawiają drogę.",
            "note": "→ Passive: The road is being repaired."
        },
        {
            "en": "Active: Someone is interviewing me.",
            "ua": "Ktoś przeprowadza ze mną wywiad.",
            "note": "→ Passive: I am being interviewed."
        }
    ],
    "warning": "📌 Znaczniki czasu (teraz, w tej chwili, obecnie) pozostają!"
}

{
    "title": "7. Czas teraźniejszy pasywny vs czas teraźniejszy ciągły",
    "intro": "Porównanie dwóch form - regularne działania vs działania w tej chwili:",
    "rows": [
        {
            "en": "The house is cleaned every week.",
            "ua": "Dom jest sprzątany co tydzień.",
            "note": "vs: Dom jest teraz sprzątany. - Dom jest teraz sprzątany."
        },
        {
            "en": "Cars are made in Germany.",
            "ua": "Maszyny produkowane są w Niemczech.",
            "note": "vs: Robi się samochód dla mnie. — Samochód jest teraz robiony dla mnie."
        },
        {
            "en": "The report is prepared monthly.",
            "ua": "Raport przygotowywany jest co miesiąc.",
            "note": "vs: Raport jest obecnie przygotowywany. — Raport jest w trakcie opracowywania."
        }
    ],
    "warning": "📌 Czas teraźniejszy prosty = regularnie, zawsze. Present Continuous = teraz, w tym momencie."
}

{
    "title": "8. Znaczniki czasu dla czasu teraźniejszego ciągłego biernego",
    "intro": "Typowe słowa i wyrażenia wskazujące na czas teraźniejszy ciągły:",
    "items": [
        {
            "label": "Teraz",
            "title": "teraz, teraz, w tej chwili, obecnie",
            "subtitle": "Raport jest właśnie pisany."
        },
        {
            "label": "Dzisiaj",
            "title": "dzisiaj, dziś rano, po południu",
            "subtitle": "Spotkanie odbędzie się dziś po południu."
        },
        {
            "label": "Ten okres",
            "title": "w tym tygodniu, w tym miesiącu, w tym roku",
            "subtitle": "W tym roku budowany jest nowy most."
        },
        {
            "label": "Tymczasowo",
            "title": "obecnie, na razie, tymczasowo",
            "subtitle": "Obecnie biuro jest w remoncie."
        }
    ]
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pomiń bycie.",
            "wrong": "The house is painted now.",
            "right": "✅ The house is being painted now."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Nieprawidłowa kolejność słów.",
            "wrong": "The report being is written.",
            "right": "✅ The report is being written."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Używanie bycia zamiast bycia.",
            "wrong": "The car is been repaired now.",
            "right": "✅ The car is being repaired now."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Pomieszanie czasu teraźniejszego prostego i ciągłego.",
            "wrong": "The house is being cleaned every day.",
            "right": "✅ The house is cleaned every day. (регулярно)"
        }
    ]
}
